// Parse Evolution payload — incoming message from professional
const body = $input.first().json.body || $input.first().json;
const data = body.data || body;
const instance = body.instance || '';
const event = body.event || 'messages.upsert';

if (event !== 'messages.upsert') {
  return [{ json: { skip: true, reason: 'not messages.upsert' } }];
}

const key = data.key || {};
if (key.fromMe) {
  return [{ json: { skip: true, reason: 'fromMe' } }];
}

const rawJid = key.remoteJid || '';
// Skip group messages (g.us), broadcasts, newsletters
if (rawJid.includes('@g.us') || rawJid.includes('@broadcast') || rawJid.includes('@newsletter')) {
  return [{ json: { skip: true, reason: 'group/broadcast', remoteJid: rawJid } }];
}

const msg = data.message || {};
const text = msg.conversation || msg.extendedTextMessage?.text || '';
if (!text) {
  return [{ json: { skip: true, reason: 'no text' } }];
}

// Multi-device LID: remoteJid = '<lid>@lid', phone real em key.senderPn
// Fallback chain: senderPn → participantPn → remoteJid (se for @s.whatsapp.net)
let phoneSource = '';
if (rawJid.includes('@lid') && key.senderPn) {
  phoneSource = key.senderPn;
} else if (key.senderPn) {
  phoneSource = key.senderPn;
} else if (key.participantPn) {
  phoneSource = key.participantPn;
} else {
  phoneSource = rawJid;
}
const phone = phoneSource.replace(/@.*/, '').replace(/\D/g,'');

if (!phone || phone.length < 10) {
  return [{ json: { skip: true, reason: 'no phone resolvable', rawJid, senderPn: key.senderPn||null } }];
}

return [{ json: {
  skip: false,
  phone,
  text: text.trim(),
  instance,
  remoteJid: rawJid,
  replyTo: rawJid,
  messageId: key.id || '',
  pushName: data.pushName || '',
}}];

// ── MIRA BRAIN ───────────────────────────────────────────
// Auth + Intent (regex Tier 1) + RPC call + Format WhatsApp markdown

const SUPABASE_URL = 'https://oqboitkpcvuaudouwvkl.supabase.co';
const SUPABASE_KEY = 'REDACTED_USE_N8N_CREDENTIALS';

const input = $input.first().json;
const phone = input.phone;
const text = input.text;
const instance = input.instance;

const httpRequest = this.helpers.httpRequest.bind(this);
async function rpc(name, params) {
  try {
    return await httpRequest({
      method: 'POST',
      url: `${SUPABASE_URL}/rest/v1/rpc/${name}`,
      headers: {
        apikey: SUPABASE_KEY,
        Authorization: 'Bearer ' + SUPABASE_KEY,
      },
      body: params,
      json: true,
    });
  } catch (e) {
    throw new Error(`rpc ${name}: ${e.message || e}`);
  }
}

// ── Date helpers ───────────────────────────
function pad(n){ return n<10?'0'+n:''+n; }
function isoDate(d){ return d.getFullYear()+'-'+pad(d.getMonth()+1)+'-'+pad(d.getDate()); }
function today(){ return new Date(); }
function tomorrow(){ const d=new Date(); d.setDate(d.getDate()+1); return d; }
function monthRange(){ const d=new Date(); return { start: isoDate(new Date(d.getFullYear(),d.getMonth(),1)), end: isoDate(new Date(d.getFullYear(),d.getMonth()+1,0)) }; }
function weekRange(){ const d=new Date(), day=d.getDay(); const mon=new Date(d); mon.setDate(d.getDate()-((day+6)%7)); const sun=new Date(mon); sun.setDate(mon.getDate()+6); return { start: isoDate(mon), end: isoDate(sun) }; }
function todayRange(){ const t=isoDate(today()); return { start:t, end:t }; }
function money(n){ if(n==null||isNaN(n)) return 'R$ 0,00'; return 'R$ '+Number(n).toFixed(2).replace('.',',').replace(/\B(?=(\d{3})+(?!\d))/g,'.'); }
function brDate(d){ if(typeof d==='string') d=new Date(d+'T12:00:00'); return pad(d.getDate())+'/'+pad(d.getMonth()+1); }
function bold(s){ return '*'+s+'*'; }
const LINE = '─────────────';

function extractName(t){ return (t||'').replace(/\b(quem|e|é|paciente|cliente|telefone|contato|whats|whatsapp|de|do|da|quanto|saldo|deve|devendo|me|a|o|esta|está)\b/gi,' ').replace(/[?!.]/g,'').replace(/\s+/g,' ').trim(); }
function periodFromText(t){ t=(t||'').toLowerCase(); if(/hoje|do dia/.test(t)) return { label:'hoje', ...todayRange() }; if(/semana/.test(t)) return { label:'essa semana', ...weekRange() }; return { label:'esse mes', ...monthRange() }; }

// ── Intent parser ──────────────────────────
const INTENTS = [
  { intent:'help',           re: /^\s*(\/?ajuda|\/?help|comandos|menu|opcoes|opções)\s*$/i },
  { intent:'greeting',       re: /^\s*(oi|ola|olá|bom dia|boa tarde|boa noite|hey|hello|e ai)\s*[!?.]*\s*$/i },
  { intent:'agenda_today',   re: /(agenda|horario|atendimento).*(hoje|do dia)|tenho hoje|tenho agenda hoje|quem.*hoje/i },
  { intent:'agenda_tomorrow',re: /(agenda|horario|atendimento).*(amanha|amanhã)|tenho amanha|tenho amanhã/i },
  { intent:'agenda_week',    re: /(agenda|horario).*(semana|esta semana)|minha semana/i },
  { intent:'agenda_free',    re: /(horario|horarios).*(livre|livres|disponivel|disponiveis|vazio)|tem horario|esta livre/i },
  { intent:'payments_list',re: /(quem|quais)\s+(me\s+)?(fez|fizeram|pag\w*).*(hoje|semana|mes|mês)|pagamentos?\s+(de\s+)?(hoje|essa\s+semana|este\s+mes|do\s+mes|do\s+mês)|quem\s+me\s+pag\w+/i },
  { intent:'finance_revenue',re: /(faturei|faturamento|receita|fatura|recebi).*(hoje|semana|mes|mês)|receita.*(semana|mes|mês|hoje)/i },
  { intent:'finance_commission', re: /(minha\s+)?(comissao|comissão)|quanto\s+ganhei/i },
  { intent:'patient_balance',re: /(quanto\s+(a\s+|o\s+)?[a-zA-Z]+\s+(me\s+)?deve|saldo\s+(do|da|de)\s+[a-zA-Z]+|devendo\s+[a-zA-Z]+)/i },
  { intent:'patient_lookup', re: /(paciente|cliente|quem\s+(e|é|eh))\s+[a-zA-Z]+/i },
];
function parseIntent(t){ for (const p of INTENTS) if (p.re.test(t)) return p.intent; return 'unknown'; }

// ── Formatters ─────────────────────────────
function fmtHelp(name){ return `Oi ${name||'Doutor(a)'}! 👋\n\nTenho 3 areas:\n📋 ${bold('/pacientes')} — busca, saldo\n📅 ${bold('/agenda')} — sua agenda, horarios livres\n💰 ${bold('/financeiro')} — receita, comissao\n\nPode falar portugues normal.`; }
function fmtGreeting(name){ return `Oi ${name||'Doutor(a)'}! Sou a Mira, sua assistente. Diga ${bold('/ajuda')} pra ver o que posso fazer.`; }
function fmtUnknown(){ return `🤔 Nao entendi ainda.\n\nExemplos:\n• "tenho agenda hoje?"\n• "quanto faturei essa semana?"\n• "qual minha comissao do mes?"\n• "quem e a Maria Silva?"\n\nDigite ${bold('/ajuda')}.`; }
function fmtAgenda(data,label){ if(!data?.appointments?.length) return `📅 ${bold('Agenda — '+(label||data?.date||''))}\n\nNenhum agendamento.`; const lines=[`📅 ${bold('Agenda — '+(label||data.date))}`,LINE]; data.appointments.forEach(a=>{ const time=(a.time||'').substring(0,5); const st=a.status==='finalizado'?'✅':(a.status==='cancelado'?'❌':'⏳'); lines.push(`${st} ${bold(time)} — ${a.patient||'Sem nome'}${a.procedure?' · '+a.procedure:''}`); }); lines.push(LINE); lines.push(`Total: ${bold(data.total)} · Finalizados: ${data.finalized} · Pendentes: ${data.pending}`); return lines.join('\n'); }
function fmtFreeSlots(data,label){ if(!data?.busy?.length) return `🟢 ${bold('Horarios — '+(label||data?.date||''))}\n\nDia totalmente livre.`; const lines=[`📅 ${bold('Ocupados — '+(label||data.date))}`,LINE]; data.busy.forEach(b=>{ const s=(b.start_time||'').substring(0,5); const e=(b.end_time||'').substring(0,5); lines.push(`🔴 ${bold(s+(e?'–'+e:''))} — ${b.patient||'Reservado'}`); }); return lines.join('\n'); }
function fmtPatientList(data){ if(!data?.results?.length) return `🔍 Nenhum paciente encontrado para "${data?.query||''}".`; const lines=[`👥 ${bold('Pacientes encontrados')}`,LINE]; data.results.forEach((r,i)=>{ lines.push(`${i+1}. ${bold(r.name)}${r.phone?' · '+r.phone:''}`); const meta=[]; if(r.phase) meta.push('fase: '+r.phase); if(r.temperature) meta.push('temp: '+r.temperature); if(meta.length) lines.push('   '+meta.join(' · ')); }); return lines.join('\n'); }
function fmtPatientBalance(data){ if(!data?.patient) return '🔍 Paciente nao encontrado.'; const p=data.patient; const lines=[`💰 ${bold('Saldo — '+p.name)}`,LINE,`Total: ${bold(money(data.total))}`,`Pago: ${money(data.paid)}`,`Saldo devedor: ${bold(money(data.balance))}`]; if(data.appointments?.length){ lines.push(LINE); lines.push(bold('Atendimentos:')); data.appointments.slice(0,5).forEach(a=>{ const saldo=Math.max(0,Number(a.value||0)-Number(a.paid||0)); lines.push(`• ${brDate(a.date)} — ${a.procedure||'s/proc'} · ${money(a.value)} (saldo ${money(saldo)})`); }); } return lines.join('\n'); }
function fmtFinanceSummary(data,label){ if(!data) return 'Sem dados financeiros.'; const lines=[`💰 ${bold('Receita — '+(label||'periodo'))}`,LINE,`Bruto: ${bold(money(data.bruto))}`,`Atendimentos: ${data.qtd}`,`Ticket medio: ${money(data.ticket_medio)}`]; if(data.delta_pct!=null){ const arrow=data.delta_pct>=0?'📈':'📉'; const pct=(data.delta_pct>=0?'+':'')+Number(data.delta_pct).toFixed(1).replace('.',',')+'%'; lines.push(`${arrow} vs anterior: ${pct} (${money(data.previous_bruto)})`); } return lines.join('\n'); }
function fmtFinanceCommission(data,label){ if(!data) return 'Sem dados de comissao.'; return [`💼 ${bold('Comissao — '+(label||'periodo'))}`,LINE,`Bruto gerado: ${money(data.bruto)}`,`Comissao: ${bold(money(data.comissao))}`,`Percentual efetivo: ${Number(data.percentual||0).toFixed(1).replace('.',',')}%`].join('\n'); }
function fmtPaymentsList(data,label){ if(!data?.payments?.length) return `💸 ${bold('Pagamentos — '+(label||'periodo'))}\n\nNenhum pagamento no periodo.`; const lines=[`💸 ${bold('Pagamentos — '+(label||'periodo'))}`,LINE]; data.payments.slice(0,15).forEach(p=>{ const m=p.method?' · '+p.method:''; lines.push(`• ${brDate(p.date)} ${bold(money(p.value))}${m} — ${p.patient||'?'}`); }); if(data.payments.length>15) lines.push(`... e mais ${data.payments.length-15}`); lines.push(LINE); lines.push(`Total: ${bold(money(data.sum))} em ${data.total} pagamento(s)`); return lines.join('\n'); }
function fmtRpcError(d){ if(!d) return '⚠️ Sem resposta.'; if(d.error==='unauthorized') return '🔒 Voce nao tem permissao. Fale com o admin.'; if(d.error==='patient_not_found') return '🔍 Paciente nao encontrado.'; if(d.error==='query_too_short') return '🔍 Termo muito curto.'; return '⚠️ '+(d.error||'erro'); }

// ── Main flow ──────────────────────────────
let reply = '';
try {
  // 1) Auth
  const auth = await rpc('wa_pro_authenticate', { p_phone: phone });
  if (!auth || auth.ok === false) {
    reply = '🔒 Numero nao cadastrado. Fale com o admin pra liberar acesso.';
  } else {
    const profName = (auth.name || auth.label || '').split(' ')[0] || 'Doutor(a)';
    const intent = parseIntent(text);

    if (intent === 'help') reply = fmtHelp(profName);
    else if (intent === 'greeting') reply = fmtGreeting(profName);
    else if (intent === 'agenda_today')   { const r = await rpc('wa_pro_agenda',{p_phone:phone,p_date:isoDate(today())});     reply = r?.ok===false ? fmtRpcError(r) : fmtAgenda(r,'hoje'); }
    else if (intent === 'agenda_tomorrow'){ const r = await rpc('wa_pro_agenda',{p_phone:phone,p_date:isoDate(tomorrow())});  reply = r?.ok===false ? fmtRpcError(r) : fmtAgenda(r,'amanha'); }
    else if (intent === 'agenda_week')    { const r = await rpc('wa_pro_agenda',{p_phone:phone,p_date:isoDate(today())});     reply = r?.ok===false ? fmtRpcError(r) : fmtAgenda(r,'hoje'); }
    else if (intent === 'agenda_free')    { const r = await rpc('wa_pro_agenda_free_slots',{p_phone:phone,p_date:isoDate(today())}); reply = r?.ok===false ? fmtRpcError(r) : fmtFreeSlots(r,'hoje'); }
    else if (intent === 'patient_lookup') { const name=extractName(text); if(name.length<2) reply='🔍 Diga o nome do paciente.'; else { const r=await rpc('wa_pro_patient_search',{p_phone:phone,p_query:name,p_limit:5}); reply = r?.ok===false ? fmtRpcError(r) : fmtPatientList(r); } }
    else if (intent === 'patient_balance'){ const name=extractName(text); if(name.length<2) reply='🔍 Diga o nome do paciente.'; else { const r=await rpc('wa_pro_patient_balance',{p_phone:phone,p_patient_query:name}); reply = r?.ok===false ? fmtRpcError(r) : fmtPatientBalance(r); } }
    else if (intent === 'payments_list'){ const per=periodFromText(text); const r=await rpc('wa_pro_recent_payments',{p_phone:phone,p_start_date:per.start,p_end_date:per.end}); reply = r?.ok===false ? fmtRpcError(r) : fmtPaymentsList(r,per.label); }
    else if (intent === 'finance_revenue'){ const per=periodFromText(text); const r=await rpc('wa_pro_finance_summary',{p_phone:phone,p_start_date:per.start,p_end_date:per.end}); reply = r?.ok===false ? fmtRpcError(r) : fmtFinanceSummary(r,per.label); }
    else if (intent === 'finance_commission'){ const per=periodFromText(text); const r=await rpc('wa_pro_finance_commission',{p_phone:phone,p_start_date:per.start,p_end_date:per.end}); reply = r?.ok===false ? fmtRpcError(r) : fmtFinanceCommission(r,per.label); }
    else reply = fmtUnknown();

    // 2) Audit log (best-effort)
    try {
      await rpc('wa_pro_log_query', {
        p_phone: phone,
        p_professional_id: auth.professional_id,
        p_wa_number_id: auth.wa_number_id || null,
        p_query: text,
        p_intent: intent,
        p_response: reply.slice(0,500),
        p_success: true,
        p_error: null,
        p_tokens_used: 0,
        p_response_ms: null,
      });
    } catch(e) { /* ignore audit errors */ }
  }
} catch (err) {
  reply = '⚠️ Erro interno: ' + (err.message||'desconhecido').slice(0,200);
}

return [{ json: { phone, instance, reply, originalText: text } }];
